#include <iostream>
#include <cstring>

class MyString {
private:
    char* data;
    size_t len;

public:
    MyString() : data(nullptr), len(0) {
        data = new char[1];
        data[0] = '\0';
    }

    MyString(const char* s) : data(nullptr), len(0) {
        if (s == nullptr) {
            data = new char[1];
            data[0] = '\0';
            len = 0;
        } else {
            len = std::strlen(s);
            data = new char[len + 1];
            std::strcpy(data, s);
        }
    }

    MyString(const MyString& other) : len(other.len) {
        data = new char[len + 1];
        std::strcpy(data, other.data);
    }

    ~MyString() {
        delete[] data;
        data = nullptr;
    }

    void display() const {
        std::cout << data;
    }

    size_t getLength() const {
        std::cout << len;
    }

    const char* c_str() const {
        return data;
    }
};

int main() {
    MyString s1("Hello, C++!");
    std::cout << "s1: ";
    s1.display();
    std::cout << " (Length: "; s1.getLength(); std::cout << ")\n";

    MyString s2 = s1;
    std::cout << "s2 (copy of s1): ";
    s2.display();
    std::cout << " (Length: "; s2.getLength(); std::cout << ")\n";

    MyString s3("Deep Copy Test");
    std::cout << "s3: ";
    s3.display();
    std::cout << " (Length: "; s3.getLength(); std::cout << ")\n";

    MyString s4("");
    std::cout << "s4 (empty): ";
    s4.display();
    std::cout << " (Length: "; s4.getLength(); std::cout << ")\n";

    MyString s5(nullptr);
    std::cout << "s5 (from nullptr): ";
    s5.display();
    std::cout << " (Length: "; s5.getLength(); std::cout << ")\n";

    MyString s6;
    std::cout << "s6 (default): ";
    s6.display();
    std::cout << " (Length: "; s6.getLength(); std::cout << ")\n";

    return 0;
}
